#!/usr/bin/env bash
#
# verify-all.sh - one-shot health check for the monster-family accountable-agent
# stack. Answers a single question: "is the stack green?"
#
# It runs, in order, each as a labeled step with its own PASS/FAIL and wall-clock:
#
#   1. BUILD - release-build the three crates (monster-guard, monster-swarm,
#              monster-resident) and, if a quality knot is present, the two
#              distributed-inference binaries the demo/tests need
#              (paris-probe-rknot, fat-station). Per-crate build time captured.
#   2. TEST  - `cargo test --release` in monster-swarm. The heavy paris_subagent /
#              quality_corpus tests SKIP without a knot (expected, not a failure).
#   3. DEMO  - `scripts/demo-admission.sh`. Fails if it exits nonzero OR any gate
#              verdict line (a leading "FAIL " - NOT the probe diagnostic "FAIL:")
#              is emitted.
#   4. BENCH - `scripts/bench-admission.sh` with a small BENCH_RUNS for speed.
#              Informational: the overall verdict does NOT depend on bench numbers,
#              but the step fails if the bench script itself errors out.
#   5. SUMMARY - each step's PASS/FAIL + time, the total wall-clock, and one
#              overall verdict line. Exit 0 only if BUILD+TEST+DEMO all passed.
#
# This institutionalizes the repo policy "keep the touched scope green."
#
# Usage:
#   bash scripts/verify-all.sh            # quiet: only failures + summary
#   bash scripts/verify-all.sh --verbose  # stream every sub-command's output
#
# No emojis. No git. No commit/push. Plain ASCII only. It changes nothing outside
# its own temp logs (the demo/bench manage their own isolated MONSTER_GUARD_HOMEs).

# NOT set -e: we want to run every step and aggregate, capturing each status
# explicitly, instead of aborting on the first failure.
set -uo pipefail

# ---------------------------------------------------------------------------
# Resolve the tree relative to THIS script so it runs from anywhere.
# ---------------------------------------------------------------------------
script_dir="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
swarm_dir="$(cd "${script_dir}/.." && pwd)"          # .../gnosis/monster-swarm
gnosis_dir="$(cd "${swarm_dir}/.." && pwd)"          # .../gnosis
di_dir="${gnosis_dir}/distributed-inference"

DEMO_SCRIPT="${script_dir}/demo-admission.sh"
BENCH_SCRIPT="${script_dir}/bench-admission.sh"

# Knot used by the quality probe. If present, the demo's Gate A exercises the
# real probe and the build step also builds the DI probe/fat-station binaries.
KNOT_PATH="${HOME}/.edgework/models/qwen2.5-0.5b-instruct.knot"

# Fixed-small bench sample count for speed (overridable from the environment).
BENCH_RUNS="${BENCH_RUNS:-5}"

# ---------------------------------------------------------------------------
# Flags.
# ---------------------------------------------------------------------------
VERBOSE=0
for arg in "$@"; do
  case "${arg}" in
    --verbose|-v) VERBOSE=1 ;;
    --help|-h)
      grep -E '^#( |$)' "${BASH_SOURCE[0]}" | sed 's/^# \{0,1\}//'
      exit 0
      ;;
    *)
      echo "verify-all: unknown argument: ${arg}" >&2
      echo "usage: bash scripts/verify-all.sh [--verbose]" >&2
      exit 2
      ;;
  esac
done

# ---------------------------------------------------------------------------
# Temp logs (quiet mode captures sub-output here; surfaced only on failure).
# ---------------------------------------------------------------------------
LOG_DIR="$(mktemp -d "${TMPDIR:-/tmp}/verify-all.XXXXXX")"

cleanup() {
  # Reap any stray sleep nodes / guard supervisors a sub-step may have left,
  # then drop our temp logs. The demo/bench scripts each clean up their own temp
  # homes via their EXIT traps; this is belt-and-braces for stragglers.
  pkill -f "monster-guard run" 2>/dev/null || true
  pkill -f "/bin/sleep 3600" 2>/dev/null || true
  pkill -f "/bin/sleep 1" 2>/dev/null || true
  # Remove any orphaned demo/bench temp homes left behind by an aborted sub-step.
  rm -rf "${TMPDIR:-/tmp}"/monster-admission-demo.* 2>/dev/null || true
  rm -rf "${TMPDIR:-/tmp}"/bench-admission.* 2>/dev/null || true
  rm -f  "${TMPDIR:-/tmp}"/bench-homes.* 2>/dev/null || true
  [[ -n "${LOG_DIR:-}" && -d "${LOG_DIR}" ]] && rm -rf "${LOG_DIR}"
}
trap cleanup EXIT INT TERM

# ---------------------------------------------------------------------------
# Output helpers (plain ASCII only).
# ---------------------------------------------------------------------------
banner() {
  echo
  echo "============================================================"
  echo "  $*"
  echo "============================================================"
}

# Wall clock in integer milliseconds (Time::HiRes ships with macOS perl).
now_ms() { perl -MTime::HiRes=time -e 'printf "%d\n", time()*1000'; }

# Pretty "1m23.4s" / "4.2s" from a millisecond delta.
fmt_ms() {
  local ms="$1"
  awk -v ms="${ms}" 'BEGIN{
    s = ms/1000.0;
    if (s >= 60) { m = int(s/60); r = s - m*60; printf "%dm%04.1fs", m, r }
    else { printf "%.1fs", s }
  }'
}

# Run a command. In --verbose, stream live; otherwise capture to a log file and
# only surface it on failure. $1 = log file, rest = command. Returns its status.
run_step_cmd() {
  local log="$1"; shift
  if [[ "${VERBOSE}" -eq 1 ]]; then
    "$@" 2>&1 | tee "${log}"
    return "${PIPESTATUS[0]}"
  else
    "$@" >"${log}" 2>&1
    return $?
  fi
}

# Surface a captured log when a quiet step failed.
dump_log_on_fail() {
  local label="$1" log="$2"
  if [[ "${VERBOSE}" -eq 0 && -f "${log}" ]]; then
    echo "  --- ${label} output (captured) ---"
    sed 's/^/  | /' "${log}"
    echo "  --- end ${label} output ---"
  fi
}

# ---------------------------------------------------------------------------
# Per-step result accounting.
# ---------------------------------------------------------------------------
BUILD_STATUS="SKIP"; BUILD_MS=0
TEST_STATUS="SKIP";  TEST_MS=0
DEMO_STATUS="SKIP";  DEMO_MS=0
BENCH_STATUS="SKIP"; BENCH_MS=0
BUILD_DETAIL=""   # per-crate timing lines for the summary

FAILED_STEPS=()   # names of steps that gate the overall verdict and failed

overall_start="$(now_ms)"

banner "verify-all - monster-family stack health check"
echo "gnosis dir : ${gnosis_dir}"
echo "swarm  dir : ${swarm_dir}"
echo "knot       : $([[ -f "${KNOT_PATH}" ]] && echo "present (${KNOT_PATH})" || echo "ABSENT (heavy quality steps will SKIP)")"
echo "mode       : $([[ "${VERBOSE}" -eq 1 ]] && echo verbose || echo quiet)"
echo "bench runs : ${BENCH_RUNS}"
echo "logs       : ${LOG_DIR}"

# ===========================================================================
# STEP 1 - BUILD
# ===========================================================================
banner "STEP 1/5 BUILD - release-build the crates"
build_start="$(now_ms)"
build_ok=1

# crate name : crate dir : extra cargo args. The three monster crates always
# build; the DI binaries only build when a quality knot is present (the demo's
# Gate A and the heavy tests need the probe binary, but skip without a knot).
build_targets=(
  "monster-guard|${gnosis_dir}/monster-guard|"
  "monster-swarm|${gnosis_dir}/monster-swarm|"
  "monster-resident|${gnosis_dir}/monster-resident|"
)
if [[ -f "${KNOT_PATH}" ]]; then
  build_targets+=(
    "paris-probe-rknot|${di_dir}|--bin paris-probe-rknot"
    "fat-station|${di_dir}|--bin fat-station"
  )
else
  echo "note: knot absent -> NOT building paris-probe-rknot / fat-station (demo/tests will SKIP the probe)."
fi

for spec in "${build_targets[@]}"; do
  IFS='|' read -r bname bdir bargs <<<"${spec}"
  if [[ ! -d "${bdir}" ]]; then
    echo "  BUILD ${bname}: FAIL - crate dir not found: ${bdir}"
    build_ok=0
    continue
  fi
  log="${LOG_DIR}/build-${bname}.log"
  c_start="$(now_ms)"
  # shellcheck disable=SC2086  # bargs is an intentional, controlled word-split.
  ( cd "${bdir}" && run_step_cmd "${log}" cargo build --release ${bargs} )
  rc=$?
  c_ms=$(( $(now_ms) - c_start ))
  if [[ ${rc} -eq 0 ]]; then
    echo "  BUILD ${bname}: PASS - $(fmt_ms ${c_ms})"
    BUILD_DETAIL+="    ${bname}: PASS ($(fmt_ms ${c_ms}))"$'\n'
  else
    echo "  BUILD ${bname}: FAIL - rc=${rc} ($(fmt_ms ${c_ms}))"
    BUILD_DETAIL+="    ${bname}: FAIL (rc=${rc}, $(fmt_ms ${c_ms}))"$'\n'
    dump_log_on_fail "build ${bname}" "${log}"
    build_ok=0
  fi
done

BUILD_MS=$(( $(now_ms) - build_start ))
if [[ ${build_ok} -eq 1 ]]; then
  BUILD_STATUS="PASS"
  echo "STEP 1 BUILD: PASS - $(fmt_ms ${BUILD_MS})"
else
  BUILD_STATUS="FAIL"
  FAILED_STEPS+=("build")
  echo "STEP 1 BUILD: FAIL - $(fmt_ms ${BUILD_MS})"
fi

# ===========================================================================
# STEP 2 - TEST (cargo test --release in monster-swarm)
# ===========================================================================
banner "STEP 2/5 TEST - cargo test --release (monster-swarm)"
test_start="$(now_ms)"
TEST_LOG="${LOG_DIR}/test.log"

if [[ "${BUILD_STATUS}" != "PASS" ]]; then
  # We still try to test (incremental), but record that build was red.
  echo "note: BUILD was not green; running tests anyway against whatever built."
fi

( cd "${gnosis_dir}/monster-swarm" && run_step_cmd "${TEST_LOG}" cargo test --release )
test_rc=$?
TEST_MS=$(( $(now_ms) - test_start ))

# Aggregate the cargo result lines for the summary regardless of verbosity.
test_summary_lines="$(grep -E '^test result:' "${TEST_LOG}" 2>/dev/null || true)"
test_failed_count="$(grep -cE '^test result:.* [1-9][0-9]* failed' "${TEST_LOG}" 2>/dev/null || true)"
# A SKIP (heavy paris_subagent / quality_corpus tests with no knot) is reported
# by the test harness as "ignored" or as a guarded early-return; it is NOT a
# failure. We fail ONLY on cargo's own nonzero status backed by a real failure.
if [[ ${test_rc} -eq 0 ]]; then
  TEST_STATUS="PASS"
  echo "STEP 2 TEST: PASS - $(fmt_ms ${TEST_MS})"
  [[ -n "${test_summary_lines}" ]] && echo "${test_summary_lines}" | sed 's/^/  /'
else
  TEST_STATUS="FAIL"
  FAILED_STEPS+=("test")
  echo "STEP 2 TEST: FAIL - rc=${test_rc} ($(fmt_ms ${TEST_MS}))"
  [[ -n "${test_summary_lines}" ]] && echo "${test_summary_lines}" | sed 's/^/  /'
  dump_log_on_fail "test" "${TEST_LOG}"
fi

# ===========================================================================
# STEP 3 - DEMO (scripts/demo-admission.sh)
# ===========================================================================
banner "STEP 3/5 DEMO - demo-admission.sh"
demo_start="$(now_ms)"
DEMO_LOG="${LOG_DIR}/demo.log"

if [[ ! -x "${DEMO_SCRIPT}" && ! -f "${DEMO_SCRIPT}" ]]; then
  echo "STEP 3 DEMO: FAIL - demo script not found at ${DEMO_SCRIPT}"
  DEMO_STATUS="FAIL"; FAILED_STEPS+=("demo")
else
  # Always capture the demo to a log so we can count gate verdicts even in
  # verbose mode (run_step_cmd tees in verbose, redirects in quiet).
  run_step_cmd "${DEMO_LOG}" bash "${DEMO_SCRIPT}"
  demo_rc=$?
  DEMO_MS=$(( $(now_ms) - demo_start ))

  # Gate verdicts the demo prints are "PASS - ..." and "FAIL - ..." (space +
  # dash/em-dash). The demo's intentionally-bad qspec ALSO emits a raw probe
  # diagnostic containing "FAIL:" (with a COLON) which is NOT a gate verdict.
  # Match gate verdicts as a line beginning with "PASS "/"FAIL " (after optional
  # leading whitespace) and exclude the "FAIL:" colon form.
  pass_gates="$(grep -cE '^[[:space:]]*PASS[[:space:]][^:]' "${DEMO_LOG}" 2>/dev/null || true)"
  fail_gates="$(grep -E '^[[:space:]]*FAIL[[:space:]]' "${DEMO_LOG}" 2>/dev/null | grep -vE '^[[:space:]]*FAIL:' | grep -c . || true)"
  # Normalize possible empty/newline artifacts to integers.
  pass_gates=$(( pass_gates + 0 )); fail_gates=$(( fail_gates + 0 ))

  echo "  gate verdicts: ${pass_gates} PASS, ${fail_gates} FAIL (demo exit rc=${demo_rc})"

  if [[ ${demo_rc} -eq 0 && ${fail_gates} -eq 0 ]]; then
    DEMO_STATUS="PASS"
    echo "STEP 3 DEMO: PASS - $(fmt_ms ${DEMO_MS})"
  else
    DEMO_STATUS="FAIL"; FAILED_STEPS+=("demo")
    echo "STEP 3 DEMO: FAIL - rc=${demo_rc}, fail_gates=${fail_gates} ($(fmt_ms ${DEMO_MS}))"
    # Surface the offending gate lines + the captured log on failure.
    if [[ ${fail_gates} -gt 0 ]]; then
      echo "  --- failing gate lines ---"
      grep -E '^[[:space:]]*FAIL[[:space:]]' "${DEMO_LOG}" | grep -vE '^[[:space:]]*FAIL:' | sed 's/^/  | /'
    fi
    dump_log_on_fail "demo" "${DEMO_LOG}"
  fi
fi
[[ ${DEMO_MS} -eq 0 ]] && DEMO_MS=$(( $(now_ms) - demo_start ))

# ===========================================================================
# STEP 4 - BENCH (scripts/bench-admission.sh) - informational
# ===========================================================================
banner "STEP 4/5 BENCH - bench-admission.sh (BENCH_RUNS=${BENCH_RUNS})"
bench_start="$(now_ms)"
BENCH_LOG="${LOG_DIR}/bench.log"

if [[ ! -f "${BENCH_SCRIPT}" ]]; then
  echo "STEP 4 BENCH: FAIL - bench script not found at ${BENCH_SCRIPT}"
  BENCH_STATUS="FAIL"   # the bench SCRIPT erroring is a real failure...
else
  BENCH_RUNS="${BENCH_RUNS}" run_step_cmd "${BENCH_LOG}" \
    env BENCH_RUNS="${BENCH_RUNS}" bash "${BENCH_SCRIPT}"
  bench_rc=$?
  BENCH_MS=$(( $(now_ms) - bench_start ))

  # Always echo the results table (bench numbers are informational output).
  bench_table="$(sed -n '/^results (median/,/reap --cascade/p' "${BENCH_LOG}" 2>/dev/null || true)"
  if [[ -n "${bench_table}" ]]; then
    echo "${bench_table}" | sed 's/^/  /'
  elif [[ "${VERBOSE}" -eq 0 ]]; then
    # No parseable table; surface whatever the bench printed.
    sed 's/^/  /' "${BENCH_LOG}"
  fi

  if [[ ${bench_rc} -eq 0 ]]; then
    BENCH_STATUS="PASS"
    echo "STEP 4 BENCH: PASS - $(fmt_ms ${BENCH_MS}) (informational; does not gate the verdict)"
  else
    BENCH_STATUS="FAIL"
    echo "STEP 4 BENCH: FAIL - the bench script errored (rc=${bench_rc}) ($(fmt_ms ${BENCH_MS}))"
    dump_log_on_fail "bench" "${BENCH_LOG}"
  fi
fi
# NOTE: BENCH does NOT gate the overall verdict (per spec), so it is not added
# to FAILED_STEPS. Bench numbers are informational; only BUILD+TEST+DEMO gate.

# ===========================================================================
# STEP 5 - SUMMARY
# ===========================================================================
overall_ms=$(( $(now_ms) - overall_start ))

banner "STEP 5/5 SUMMARY"
printf '  %-7s %-5s %s\n' "STEP" "STATE" "TIME"
printf '  %-7s %-5s %s\n' "-----" "-----" "----"
printf '  %-7s %-5s %s\n' "BUILD" "${BUILD_STATUS}" "$(fmt_ms ${BUILD_MS})"
if [[ -n "${BUILD_DETAIL}" ]]; then
  printf '%s' "${BUILD_DETAIL}"
fi
printf '  %-7s %-5s %s\n' "TEST"  "${TEST_STATUS}"  "$(fmt_ms ${TEST_MS})"
printf '  %-7s %-5s %s\n' "DEMO"  "${DEMO_STATUS}"  "$(fmt_ms ${DEMO_MS})"
printf '  %-7s %-5s %s\n' "BENCH" "${BENCH_STATUS}" "$(fmt_ms ${BENCH_MS}) (informational)"
echo
echo "  total wall-clock: $(fmt_ms ${overall_ms})"
echo

# Overall verdict: PASS only if BUILD + TEST + DEMO all passed.
if [[ ${#FAILED_STEPS[@]} -eq 0 ]]; then
  echo "verify-all: PASS"
  exit 0
else
  # Join failed gating step names for a single, clear verdict line.
  joined="$(printf '%s, ' "${FAILED_STEPS[@]}")"
  joined="${joined%, }"
  echo "verify-all: FAIL (${joined})"
  exit 1
fi
